import { Component, OnInit } from '@angular/core';
import { MaintenanceService } from '../../services/maintenance.service';
import { AuthService } from '../../services/auth.service';
import { MaintenanceRequest } from '../../models/maintenance-request.model';

@Component({
  selector: 'app-maintenance',
  templateUrl: './maintenance.component.html',
  styleUrls: ['./maintenance.component.css']
})
export class MaintenanceComponent implements OnInit {
  requests: MaintenanceRequest[] = [];
  currentUser: any;
  showForm = false;
  newRequest: MaintenanceRequest = {
    studentId: 0, studentName: '', roomId: 0, roomNumber: '',
    issueType: '', description: '', status: 'PENDING', priority: 'MEDIUM',
  };

  constructor(private maintenanceService: MaintenanceService, private authService: AuthService) {

  }

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadRequests();
  }

  loadRequests() {
    if (this.currentUser.role === 'STUDENT') {
      this.maintenanceService.getMaintenanceRequestsByStudent(this.currentUser.id).subscribe(data => this.requests = data);
    } else {
      this.maintenanceService.getAllMaintenanceRequests().subscribe(data => this.requests = data);
    }
  }

  createRequest() {
    this.newRequest.studentId = this.currentUser.id;
    this.newRequest.studentName = this.currentUser.firstName + ' ' + this.currentUser.lastName;
    this.newRequest.roomId = this.currentUser.roomId || 0;
    this.maintenanceService.createMaintenanceRequest(this.newRequest).subscribe({
      next: () => { this.loadRequests(); this.showForm = false; alert('Request submitted!'); },
      error: (err) => alert('Error')
    });
  }

  updateStatus(req: MaintenanceRequest, status: string) {
    const update: MaintenanceRequest = { 
      ...req, 
      status: status as any, 
      resolvedAt: this.currentUser.firstName + ' ' + this.currentUser.lastName 
    };
    this.maintenanceService.updateMaintenanceRequest(req.id!, update).subscribe({
      next: () => { alert('Status updated!'); this.loadRequests(); },
      error: (err) => alert('Error')
    });
  }

  updatePriority(req: MaintenanceRequest, priority: string) {
    const update: MaintenanceRequest = { ...req, priority: priority as any };
    this.maintenanceService.updateMaintenanceRequest(req.id!, update).subscribe({
      next: () => { alert('Priority updated!'); this.loadRequests(); },
      error: (err) => alert('Error')
    });
  }

  deleteRequest(id: number) {
    if(confirm('Delete?')) {
      this.maintenanceService.deleteMaintenanceRequest(id).subscribe(() => { alert('Deleted!'); this.loadRequests(); });
    }
  }

  canManage(): boolean { return this.currentUser.role === 'ADMIN' || this.currentUser.role === 'WARDEN'; }
  canDelete(): boolean { return this.currentUser.role === 'ADMIN'; }
}
